// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define N 200000
#define INF 1000000000
struct Point {
    int x, y, c;
};
int compare(const void *a, const void *b) {
    struct Point *p1 = (struct Point *)a;
    struct Point *p2 = (struct Point *)b;
    if (p1->x == p2->x) return p1->y - p2->y;
    return p1->x - p2->x;
}
int orientation(struct Point p, struct Point q, struct Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // collinear
    return (val > 0) ? 1 : 2; // clock or counterclock wise
}
int convexHull(struct Point points[], int n, struct Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }
    int p = l, q;
    int cnt = 0;
    do {
        hull[cnt] = points[p];
        q = (p + 1) % n;
        for (int i = 0; i < n; i++) {
            if (orientation(points[p], points[i], points[q]) == 2) q = i;
        }
        p = q;
        cnt++;
    } while (p != l);
    return cnt;
}
int lowerEnvelope(struct Point hull[], int n) {
    int envelope = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        if (hull[i].c < hull[j].c) envelope++;
    }
    return envelope;
}
int minCost(struct Point points[], int n) {
    qsort(points, n, sizeof(struct Point), compare);
    struct Point hull[N];
    int m = convexHull(points, n, hull);
    int envelope = lowerEnvelope(hull, m);
    int minCost = INF;
    for (int i = 0; i < envelope; i++) {
        int cost = 0;
        for (int j = 0; j < m; j++) {
            if (hull[j].c < hull[(j + 1) % m].c) cost += hull[j].c;
        }
        minCost = min(minCost, cost);
    }
    return minCost;
}
int main() {
    int n;
    scanf("%d", &n);
    struct Point points[N];
    for (int i = 0; i < n; i++) {
        scanf("%d %d %d", &points[i].x, &points[i].y, &points[i].c);
    }
    printf("%d\n", minCost(points, n));
    return 0;
}

